const apiResponse = $input.first().json;
const imagePrompt = apiResponse.choices?.[0]?.message?.content || '';
const upstream = $('Extract Caption').item.json;
return [{
  json: {
    date: upstream.date,
    dayIndex: upstream.dayIndex,
    human: upstream.human,
    caption: upstream.caption,
    imagePrompt: imagePrompt.trim()
  }
}];

const item = $input.first().json;
const logEntry = {
  timestamp: new Date().toISOString(),
  date: item.date,
  dayIndex: item.dayIndex,
  humanName: item.human.name,
  humanInstagram: item.human.instagram,
  humanPersona: item.human.persona,
  caption: item.caption,
  imagePrompt: item.imagePrompt,
  generatedText: item.generatedText || '',
  imageFile: item.fileName || null,
  imageSaved: item.imageSaved || false
};
return [{ json: logEntry }];

const item = $input.first().json;
// Instagram Business Account IDs - you need to get these from Facebook Business Manager
const accountMap = {
  'iamolivia.k': 'YOUR_OLIVIA_ACCOUNT_ID',
  'iampiglet.g': 'YOUR_PIGLET_ACCOUNT_ID',
  'iamandy.em': 'YOUR_ANDY_ACCOUNT_ID',
  'iamphoenix.y': 'YOUR_PHOENIX_ACCOUNT_ID'
};

return [{
  json: {
    date: item.date,
    dayIndex: item.dayIndex,
    human: item.human,
    caption: item.caption,
    imagePrompt: item.imagePrompt,
    instagramHandle: item.human.instagram,
    instagramAccountId: accountMap[item.human.instagram] || '',
    imageUrl: item.imageUrl || ''
  }
}];

// Content Recommendation Engine - Big Data Analytics
const today = new Date();
const dayOfWeek = today.getDay();

// Historical performance data (from engagement API)
const engagementData = $input.all()[0]?.json || {};
const media = engagementData.data || [];

// Analyze which themes performed best
const themePerformance = {};
const keywordMap = {
  'morning': ['morning', '早安', 'wake up', '起床', 'breakfast'],
  'coffee': ['coffee', '咖啡', 'cafe', '咖啡店', 'latte'],
  'gym': ['gym', 'workout', 'fitness', '健身', 'training', 'exercise'],
  'cooking': ['cooking', 'food', '煮飯', '美食', 'cook', 'recipe'],
  'night': ['night', 'evening', '晚上', 'relax', 'bedtime', 'sleep'],
  'street': ['street', 'ootd', 'fashion', '穿搭', 'outfit', 'style'],
  'skincare': ['skincare', 'skin', '護膚', 'beauty', 'glow', 'routine'],
  'selfcare': ['selfcare', 'sunday', '遺療', 'heal', 'rest', 'mental health']
};

// Score each post by engagement rate
media.forEach(post => {
  const caption = post.caption || '';
  const likes = post.like_count || 0;
  const comments = post.comments_count || 0;
  const engagement = likes + (comments * 3); // Weight comments more

  Object.entries(keywordMap).forEach(([theme, keywords]) => {
    if (keywords.some(kw => caption.toLowerCase().includes(kw.toLowerCase()))) {
      if (!themePerformance[theme]) themePerformance[theme] = { total: 0, count: 0 };
      themePerformance[theme].total += engagement;
      themePerformance[theme].count += 1;
    }
  });
});

// Calculate average performance per theme
const scoredThemes = Object.entries(themePerformance).map(([theme, data]) => ({
  theme,
  avgEngagement: data.count > 0 ? Math.round(data.total / data.count) : 0,
  postCount: data.count
}));

// Sort by performance
scoredThemes.sort((a, b) => b.avgEngagement - a.avgEngagement);

// Day-based theme mapping
const dayThemes = {
  0: 'selfcare',      // Sunday
  1: 'coffee',        // Monday
  2: 'gym',           // Tuesday
  3: 'cooking',       // Wednesday
  4: 'night',         // Thursday
  5: 'street',        // Friday
  6: 'morning'        // Saturday
};

// Get top performing themes
const topThemes = scoredThemes.slice(0, 3).map(t => t.theme);
const defaultTheme = dayThemes[dayOfWeek] || 'morning';

// If we have data, use best performing theme that matches today's vibe
const recommendedTheme = topThemes.length > 0 && topThemes.includes(defaultTheme) 
  ? defaultTheme 
  : (topThemes[0] || defaultTheme);

// Determine optimal posting time based on day and historical performance
const optimalTimes = {
  0: '10:00', 1: '08:00', 2: '18:00', 3: '12:00',
  4: '21:00', 5: '15:00', 6: '11:00'
};

// Seasonal/trending topics (can be enhanced with external API)
const seasonalTopics = {
  'summer': ['beach', 'vacation', 'refreshing', 'summer glow'],
  'winter': ['cozy', 'warm', 'hygge', 'winter skincare'],
  'spring': ['bloom', 'fresh start', 'detox', 'new beginnings'],
  'autumn': ['fall vibes', 'pumpkin', 'sweater weather', 'warm tones']
};

const month = today.getMonth();
let season = 'spring';
if (month >= 5 && month <= 7) season = 'summer';
else if (month >= 8 && month <= 10) season = 'autumn';
else if (month >= 11 || month <= 1) season = 'winter';

return [{
  json: {
    date: today.toISOString().split('T')[0],
    dayOfWeek,
    recommendedTheme,
    alternativeThemes: topThemes.filter(t => t !== recommendedTheme).slice(0, 2),
    optimalPostTime: optimalTimes[dayOfWeek] || '09:00',
    seasonalTopics: seasonalTopics[season] || [],
    currentSeason: season,
    engagementAnalysis: {
      totalPostsAnalyzed: media.length,
      topPerformingThemes: scoredThemes.slice(0, 5),
      rawData: themePerformance
    }
  }
}];

const apiResponse = $input.first().json;
const trendData = apiResponse.choices?.[0]?.message?.content || '{}';
let parsedTrend = {};
try {
  parsedTrend = JSON.parse(trendData);
} catch (e) {
  parsedTrend = { error: 'Failed to parse trend data', raw: trendData };
}

const recommendation = $('Content Recommender').item.json;

return [{
  json: {
    date: recommendation.date,
    dayOfWeek: recommendation.dayOfWeek,
    recommendedTheme: recommendation.recommendedTheme,
    alternativeThemes: recommendation.alternativeThemes,
    optimalPostTime: recommendation.optimalPostTime,
    seasonalTopics: recommendation.seasonalTopics,
    currentSeason: recommendation.currentSeason,
    engagementAnalysis: recommendation.engagementAnalysis,
    trendAnalysis: parsedTrend
  }
}];

const response = $input.first().json;
let imageBase64 = null;
let generatedText = '';

try {
  // Gemini returns image data in candidates[0].content.parts
  const parts = response?.candidates?.[0]?.content?.parts || [];

  for (const part of parts) {
    if (part.inlineData && part.inlineData.data) {
      imageBase64 = part.inlineData.data;
    }
    if (part.text) {
      generatedText = part.text;
    }
  }
} catch (e) {
  console.log('Error parsing Gemini response:', e);
}

const upstream = $('Extract Image Prompt').item.json;

return [{
  json: {
    date: upstream.date,
    dayIndex: upstream.dayIndex,
    human: upstream.human,
    caption: upstream.caption,
    imagePrompt: upstream.imagePrompt,
    generatedText: generatedText,
    imageBase64: imageBase64,
    imageUrl: imageBase64 ? `data:image/png;base64,${imageBase64}` : null
  }
}];

const item = $input.first().json;
const imageBase64 = item.imageBase64;
const human = item.human;
const date = item.date;

if (!imageBase64) {
  return [{ json: { ...item, imageSaved: false, imagePath: null } }];
}

// We'll use n8n's Write Binary File node instead
// This node just prepares the data
return [{
  json: {
    ...item,
    imageSaved: true,
    fileName: `${human.instagram}_${date}.png`
  }
}];
